const PUZZLES = Object.entries(libraries).flatMap(([difficulty, pairs]) =>
  pairs.map(([answer, crossing], index) => makePuzzle(difficulty, index, answer, crossing))
);

const DIFFICULTIES = {
  beginner: { label: '入門', blanks: 3, hints: 3, decoys: ['山', '水', '日'] },
  intermediate: { label: '熟手', blanks: 6, hints: 2, decoys: ['雲', '月', '花', '木'] },
  advanced: { label: '博學', blanks: 9, hints: 1, decoys: ['春', '秋', '天', '地', '人'] },
  master: { label: '宗師', blanks: 12, hints: 0, decoys: ['金', '石', '風', '雷', '雲', '霧'] }
};

const cellKey = (row, column) => `${row}:${column}`;

function validatePuzzle(puzzle) {
  const errors = [];
  if (!puzzle || !Number.isInteger(puzzle.rows) || !Number.isInteger(puzzle.columns)) return { valid: false, errors: ['題組尺寸無效。'] };
  const cells = new Map();
  for (const entry of puzzle.entries ?? []) {
    if (!/^[\u4e00-\u9fff]{4}$/.test(entry.answer ?? '')) { errors.push(`成語不是四字：${entry.id ?? 'unknown'}`); continue; }
    if (!['across', 'down'].includes(entry.direction)) { errors.push(`方向無效：${entry.id}`); continue; }
    [...entry.answer].forEach((character, index) => {
      const row = entry.row + (entry.direction === 'down' ? index : 0);
      const column = entry.column + (entry.direction === 'across' ? index : 0);
      const key = cellKey(row, column);
      if (row < 0 || column < 0 || row >= puzzle.rows || column >= puzzle.columns) errors.push(`成語超出盤面：${entry.id}`);
      if (cells.has(key) && cells.get(key) !== character) errors.push(`交叉字不一致：${key}`);
      cells.set(key, character);
    });
  }
  return { valid: errors.length === 0, errors };
}

function buildBoard(puzzle, blankCount) {
  const validation = validatePuzzle(puzzle);
  if (!validation.valid) throw new Error(validation.errors.join(' '));
  const cells = new Map();
  for (const entry of puzzle.entries) {
    [...entry.answer].forEach((answer, index) => {
      const row = entry.row + (entry.direction === 'down' ? index : 0);
      const column = entry.column + (entry.direction === 'across' ? index : 0);
      const key = cellKey(row, column);
      const existing = cells.get(key) ?? { id: key, row, column, answer, entryIds: [] };
      existing.entryIds.push(entry.id);
      cells.set(key, existing);
    });
  }
  const ordered = [...cells.values()].sort((a, b) => a.row - b.row || a.column - b.column);
  const blankCells = ordered.slice(0, Math.min(blankCount, ordered.length));
  const blankIds = new Set(blankCells.map((cell) => cell.id));
  return { ...puzzle, cells, blankCells, blankIds, entries: puzzle.entries.map((entry) => ({ ...entry })) };
}

function buildChoices(board, decoys = []) {
  return [...new Set([...board.blankCells.map((cell) => cell.answer), ...decoys])].sort((a, b) => a.localeCompare(b, 'zh-Hant'));
}

function pickPuzzle(puzzles, difficulty, excludedIds = []) {
  const excluded = new Set(Array.isArray(excludedIds) ? excludedIds : [excludedIds]);
  const matching = puzzles.filter((puzzle) => puzzle.difficulty === difficulty);
  const candidates = matching.filter((puzzle) => !excluded.has(puzzle.id));
  const pool = candidates.length ? candidates : matching;
  return pool[Math.floor(Math.random() * pool.length)] ?? null;
}

function createGameState(board, difficulty) {
  const cells = Object.fromEntries([...board.cells.values()].map((cell) => [cell.id, {
    ...cell,
    value: board.blankIds.has(cell.id) ? '' : cell.answer,
    status: board.blankIds.has(cell.id) ? 'blank' : 'given'
  }]));
  return { board, difficulty, cells, score: 0, correctCount: 0, totalBlanks: board.blankCells.length, streak: 0, mistakes: 0, hintsLeft: difficulty.hints, selectedCellId: board.blankCells[0]?.id ?? '', feedback: '', startedAt: Date.now(), completedAt: null };
}

function isComplete(state) {
  return Object.values(state.cells).filter((cell) => cell.status !== 'given').every((cell) => cell.status === 'correct' || cell.status === 'hinted');
}

function answerCell(state, cellId, character) {
  const cell = state.cells[cellId];
  if (!cell || cell.status === 'correct' || cell.status === 'hinted') return state;
  if (cell.answer !== character) return { ...state, streak: 0, mistakes: state.mistakes + 1, feedback: 'incorrect' };
  const correctCount = state.correctCount + 1;
  const points = Math.round((correctCount / state.totalBlanks) * 100);
  const cells = { ...state.cells, [cellId]: { ...cell, value: character, status: 'correct' } };
  const next = { ...state, cells, correctCount, score: points, streak: state.streak + 1, feedback: 'correct' };
  return isComplete(next) ? { ...next, completedAt: Date.now(), feedback: 'complete' } : next;
}

function useHint(state, cellId = state.selectedCellId) {
  const target = state.cells[cellId] ?? Object.values(state.cells).find((cell) => cell.status === 'blank');
  if (!target || state.hintsLeft < 1 || target.status === 'correct' || target.status === 'hinted') return state;
  const cells = { ...state.cells, [target.id]: { ...target, value: target.answer, status: 'hinted' } };
  const next = { ...state, cells, hintsLeft: state.hintsLeft - 1, feedback: 'hint' };
  return isComplete(next) ? { ...next, completedAt: Date.now(), feedback: 'complete' } : next;
}

function resetGame(state) {
  return createGameState(state.board, state.difficulty);
}

const esc=(value)=>String(value).replace(/[&<>"']/g,(c)=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[c]));
const header=()=>`<header class="masthead"><a class="logo" href="./" data-action="menu" aria-label="回到首頁"><span class="kicker">IDIOM LOOM · 01</span><span class="title">字字成章</span></a><span>交錯成語填空</span></header>`;
function renderApp(root, model){root.innerHTML=model.screen==='menu'?menu():model.screen==='complete'?results(model):game(model)}
function menu(){const difficulties=[['beginner','入門',3],['intermediate','熟手',2],['advanced','博學',1],['master','宗師',0]];return `<div class="frame">${header()}<section class="menu"><p class="kicker">選擇一張題板</p><h2>把缺的一字，放回它該在的位置。</h2><p>題庫採內建四字成語，完成後可前往教育部《成語典》查詢。</p><div class="difficulty-grid">${difficulties.map(([key,label,hints])=>`<button class="difficulty" data-action="start" data-value="${key}">${label}<br><small>${hints?`提示 ${hints} 次`:'無提示'}</small></button>`).join('')}</div></section></div>`}
function game({state,choices}){const b=state.board;let cells='';for(let r=0;r<b.rows;r++)for(let c=0;c<b.columns;c++){const cell=state.cells[`${r}:${c}`];cells+=cell?`<button class="cell used ${cell.status} ${state.selectedCellId===cell.id?'selected':''}" data-action="select" data-cell-id="${cell.id}" aria-label="第 ${r+1} 列第 ${c+1} 欄，${cell.status==='blank'?'尚未作答':cell.value}">${esc(cell.value)}</button>`:'<span class="cell"></span>'}const hint=state.hintsLeft>0?'<button class="action" data-action="hint">揭示一字</button>':'<p class="no-hint">本局無提示</p>';return `<div class="frame">${header()}<section class="game-layout"><div class="board-wrap"><div class="board" style="grid-template-columns:repeat(${b.columns},1fr)">${cells}</div></div><aside class="panel"><div class="stats"><span>分數<b>${state.score}</b></span><span>提示<b>${state.hintsLeft}</b></span></div><p class="feedback" role="status">${state.feedback==='incorrect'?'這一字不在這裡。':state.feedback==='correct'?'落印成功。':'選取空格後，從下方選字。'}</p><div class="choice-grid">${choices.map(x=>`<button class="choice" data-action="answer" data-value="${x}">${x}</button>`).join('')}</div>${hint}<button class="action" data-action="reset">重設本局</button></aside></section></div>`}
function results({state}){return `<div class="frame">${header()}<section class="results"><p class="kicker">題板完成</p><h2>這一局，落印收成。</h2><p>分數 <strong>${state.score}</strong>　錯誤 ${state.mistakes} 次</p><span class="seal">完成</span><h3>本局成語</h3><ol class="entry-list">${state.board.entries.map(e=>`<li><strong>${e.answer}</strong>｜${e.clue}<br><a href="https://dict.idioms.moe.edu.tw/search.jsp?md=2" target="_blank" rel="noopener noreferrer">前往教育部《成語典》查詢</a></li>`).join('')}</ol><button class="action" data-action="again">再玩一局</button><button class="action" data-action="menu">選擇難度</button></section></div>`}

const root=document.querySelector('#app');let screen='menu',state=null;const playedIds={};
function draw(){renderApp(root,{screen,state,choices:state?buildChoices(state.board,DIFFICULTIES[state.difficulty.key].decoys):[]})}
function start(key){const history=playedIds[key]??[];const puzzle=pickPuzzle(PUZZLES,key,history);playedIds[key]=history.length===PUZZLES.filter(p=>p.difficulty===key).length?[puzzle.id]:[...history,puzzle.id];const difficulty={...DIFFICULTIES[key],key};state=createGameState(buildBoard(puzzle,difficulty.blanks),difficulty);screen='game';draw()}
root.addEventListener('click',(event)=>{const b=event.target.closest('[data-action]');if(!b)return;const {action,value,cellId}=b.dataset;if(action==='start')start(value);if(action==='select')state={...state,selectedCellId:cellId};if(action==='answer')state=answerCell(state,state.selectedCellId,value);if(action==='hint')state=useHint(state);if(action==='reset')state=resetGame(state);if(action==='again')start(state.difficulty.key);if(action==='menu')screen='menu';if(state?.completedAt)screen='complete';draw()});
root.addEventListener('keydown',(event)=>{if(event.key==='Escape'&&state){state={...state,selectedCellId:''};draw()}});draw();
